"use client";

import { useEffect, useRef, useState } from "react";

export function WhyWeSolveSection() {
  const [isVisible, setIsVisible] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) setIsVisible(true);
      },
      { threshold: 0.2 }
    );

    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section
      id="why-we-solve"
      ref={sectionRef}
      className="relative py-24 lg:py-32 border-b border-foreground/10"
    >
      <div className="max-w-[1400px] mx-auto px-6 lg:px-12">
        <span className="inline-flex items-center gap-3 text-sm font-mono text-muted-foreground mb-6">
          <span className="w-8 h-px bg-foreground/30" />
          Por quГ© lo resolvemos
        </span>
        <p
          className={`text-2xl lg:text-4xl font-display leading-snug tracking-tight text-muted-foreground max-w-5xl transition-all duration-700 ${
            isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4"
          }`}
        >
          Porque la informaciГіn pГәblica existe, pero normalmente estГЎ dispersa, es difГӯcil de
          seguir y consume demasiado tiempo, lo que hace que muchas personas terminen
          desinformadas o desconectadas de lo que realmente sucede.
        </p>
      </div>
    </section>
  );
}
